class Solution:
    def optimalDivision(self, nums):
        n = len(nums)
        s = [str(x) for x in nums]
        if n == 1:
            return s[0]
        if n == 2:
            return s[0] + '/' + s[1]
        return s[0] + '/(' + '/'.join(s[1:]) + ')'

